const cp = require('child_process');
const input = $input.first().json;
const project = (input.params && input.params.project) || input.project || '';
const projRoot = '__PROJECT_ROOT__';
const docsDir = '__DOCUMENTS_DIR__';

if (!project) return [{json:{status:'error',error:'Missing project'}}];

const path = docsDir + '/' + project;
try {
  const output = cp.execSync('bash scripts/module-status.sh "' + path + '" 2>&1', {cwd: projRoot, timeout: 30000, encoding: 'utf8'});
  const modules = output.trim().split(String.fromCharCode(10)).filter(l => l.includes('|')).map(l => {
    const [name, status, files, lines, issues] = l.split('|');
    return {name, status, files: parseInt(files)||0, lines: parseInt(lines)||0, issues: issues||''};
  });
  return [{json:{status:'complete', project, modules}}];
} catch(e) {
  return [{json:{status:'error', error: (e.stderr||'')+e.message}}];
}
